package listers

import (
	"github.com/kcp-dev/logicalcluster/v3"

	"k8s.io/apimachinery/pkg/labels"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
	"k8s.io/client-go/tools/cache"
)

// TODO add boilerplate header

// ResourceIndexer wraps an indexer, resource, and optional namespace for a given type.
// This is intended for use by listers (generated by lister-gen) only.
type ResourceClusterIndexer[T runtime.Object] struct {
	indexer  cache.Indexer
	resource schema.GroupResource
}

// NewCluster returns a new instance of a lister (resource indexer) wrapping the given indexer
// and resource for the specified type.
// This is intended for use by listers (generated by lister-gen) only.
func NewCluster[T runtime.Object](indexer cache.Indexer, resource schema.GroupResource) ResourceClusterIndexer[T] {
	return ResourceClusterIndexer[T]{indexer: indexer, resource: resource}
}

// List lists all resources in the indexer matching the given selector.
func (l ResourceClusterIndexer[T]) List(selector labels.Selector) (ret []T, err error) {
	err = cache.ListAll(l.indexer, selector, func(m interface{}) {
		ret = append(ret, m.(T))
	})
	return ret, err
}

// WithCluster returns a ResourceIndexer with the specified cluster.
func (l ResourceClusterIndexer[T]) WithCluster(cluster logicalcluster.Name) ResourceIndexer[T] {
	ret := New[T](l.indexer, l.resource)
	ret.cluster = cluster
	return ret
}

// WithCluster returns a new copy of the ResourceIndexer with the
// specified cluster.
func (l ResourceIndexer[T]) WithCluster(cluster logicalcluster.Name) ResourceIndexer[T] {
	return ResourceIndexer[T]{
		indexer:   l.indexer,
		cluster:   cluster,
		resource:  l.resource,
		namespace: l.namespace,
	}
}

// WithNamespace returns a new copy of the ResourceIndexer with the
// specified namespace.
func (l ResourceIndexer[T]) WithNamespace(namespace string) ResourceIndexer[T] {
	return ResourceIndexer[T]{
		indexer:   l.indexer,
		cluster:   l.cluster,
		resource:  l.resource,
		namespace: namespace,
	}
}
